 40→export const parseLimitWithinRange = (value, min = NOTIFICATION_LIMIT_MIN, max = NOTIFICATION_LIMIT_MAX, fallback = NOTIFICATION_DEFAULT_LIMIT) => {
 41→    const parsed = Number.parseInt(value, 10);
 42→    if (Number.isNaN(parsed)) return fallback;
 43→    if (parsed < min || parsed > max) return null;
 44→    return parsed;
