 47→const decorateNotificationMedia = (notification) => {
 48→    if (!notification || typeof notification !== 'object') return notification;
 49→
 50→    const senderAvatarMedia = createMediaResponsePayload('avatars', notification.users?.image_url, 'card');
 51→    const journalThumbnailMedia = createMediaResponsePayload('journal-images', notification.journals?.thumbnail_url, 'card');
 52→    const journalUserAvatarMedia = createMediaResponsePayload('avatars', notification.journals?.users?.image_url, 'card');
 53→
 54→    return {
 55→        ...notification,
 56→        users: notification.users ? {
 57→            ...notification.users,
 58→            image_url: senderAvatarMedia?.preferred_url || notification.users.image_url || null,
 59→            avatar_media: senderAvatarMedia
 60→        } : notification.users,
